{"meta": null, "content": [{"type": "text", "text": "{"content":"1: //===- PassManagerImpl.h - Pass management infrastructure -------*- C++ -*-===//\n2: //\n3: // Part of the LLVM Project, under the Apache License v2.0 with LLVM Exceptions.\n4: // See https://llvm.org/LICENSE.txt for license information.\n5: // SPDX-License-Identifier: Apache-2.0 WITH LLVM-exception\n6: //\n7: //===----------------------------------------------------------------------===//\n8: /// \\file\n9: /// Provides implementations for PassManager and AnalysisManager template\n10: /// methods. These classes should be explicitly instantiated for any IR unit,\n11: /// and files doing the explicit instantiation should include this header.\n12: ///\n13: //===----------------------------------------------------------------------===//\n14: \n15: #ifndef LLVM_IR_PASSMANAGERIMPL_H\n16: #define LLVM_IR_PASSMANAGERIMPL_H\n17: \n18: #include \"llvm/IR/Function.h\"\n19: #include \"llvm/IR/PassInstrumentation.h\"\n20: #include \"llvm/IR/PassManager.h\"\n21: #include \"llvm/Support/CommandLine.h\"\n22: #include \"llvm/Support/Compiler.h\"\n23: #include \"llvm/Support/PrettyStackTrace.h\"\n24: \n25: namespace llvm {\n26: \n27: template \u003ctypename IRUnitT, typename AnalysisManagerT, typename... ExtraArgTs\u003e\n28: PreservedAnalyses PassManager\u003cIRUnitT, AnalysisManagerT, ExtraArgTs...\u003e::run(\n29:     IRUnitT \u0026IR, AnalysisManagerT \u0026AM, ExtraArgTs... ExtraArgs) {\n30:   class StackTraceEntry : public PrettyStackTraceEntry {\n31:     const PassInstrumentation \u0026PI;\n32:     IRUnitT \u0026IR;\n33:     PassConceptT *Pass = nullptr;\n34: \n35:   public:\n36:     explicit StackTraceEntry(const PassInstrumentation \u0026PI, IRUnitT \u0026IR)\n37:         : PI(PI), IR(IR) {}\n38: \n39:     void setPass(PassConceptT *P) { Pass = P; }\n40: \n41:     void print(raw_ostream \u0026OS) const override {\n42:       OS \u003c\u003c \"Running pass \\\"\";\n43:       if (Pass)\n44:         Pass-\u003eprintPipeline(OS, [this](StringRef ClassName) {\n45:           auto PassName = PI.getPassNameForClassName(ClassName);\n46:           return PassName.empty() ? ClassName : PassName;\n47:         });\n48:       else\n49:         OS \u003c\u003c \"unknown\";\n50:       OS \u003c\u003c \"\\\" on \";\n51:       printIRUnitNameForStackTrace(OS, IR);\n52:       OS \u003c\u003c \"\\n\";\n53:     }\n54:   };\n55: \n56:   PreservedAnalyses PA = PreservedAnalyses::all();\n57: \n58:   // Request PassInstrumentation from analysis manager, will use it to run\n59:   // instrumenting callbacks for the passes later.\n60:   // Here we use std::tuple wrapper over getResult which helps to extract\n61:   // AnalysisManager's arguments out of the whole ExtraArgs set.\n62:   PassInstrumentation PI =\n63:       detail::getAnalysisResult\u003cPassInstrumentationAnalysis\u003e(\n64:           AM, IR, std::tuple\u003cExtraArgTs...\u003e(ExtraArgs...));\n65: \n66:   StackTraceEntry Entry(PI, IR);\n67:   for (auto \u0026Pass : Passes) {\n68:     Entry.setPass(\u0026*Pass);\n69: \n70:     // Check the PassInstrumentation's BeforePass callbacks before running the\n71:     // pass, skip its execution completely if asked to (callback returns\n72:     // false).\n73:     if (!PI.runBeforePass\u003cIRUnitT\u003e(*Pass, IR))\n74:       continue;\n75: \n76:     PreservedAnalyses PassPA = Pass-\u003erun(IR, AM, ExtraArgs...);\n77: \n78:     // Update the analysis manager as each pass runs and potentially\n79:     // invalidates analyses.\n80:     AM.invalidate(IR, PassPA);\n81: \n82:     // Call onto PassInstrumentation's AfterPass callbacks immediately after\n83:     // running the pass.\n84:     PI.runAfterPass\u003cIRUnitT\u003e(*Pass, IR, PassPA);\n85: \n86:     // Finally, intersect the preserved analyses to compute the aggregate\n87:     // preserved set for this pass manager.\n88:     PA.intersect(std::move(PassPA));\n89:   }\n90: \n91:   // Invalidation was handled after each pass in the above loop for the\n92:   // current unit of IR. Therefore, the remaining analysis results in the\n93:   // AnalysisManager are preserved. We mark this with a set so that we don't\n94:   // need to inspect each one individually.\n95:   PA.preserveSet\u003cAllAnalysesOn\u003cIRUnitT\u003e\u003e();\n96: \n97:   return PA;\n98: }\n99: \n100: template \u003ctypename IRUnitT, typename... ExtraArgTs\u003e\n101: inline AnalysisManager\u003cIRUnitT, ExtraArgTs...\u003e::AnalysisManager() = default;\n102: \n103: template \u003ctypename IRUnitT, typename... ExtraArgTs\u003e\n104: inline AnalysisManager\u003cIRUnitT, ExtraArgTs...\u003e::AnalysisManager(\n105:     AnalysisManager \u0026\u0026) = default;\n106: \n107: template \u003ctypename IRUnitT, typename... ExtraArgTs\u003e\n108: inline AnalysisManager\u003cIRUnitT, ExtraArgTs...\u003e \u0026\n109: AnalysisManager\u003cIRUnitT, ExtraArgTs...\u003e::operator=(AnalysisManager \u0026\u0026) =\n110:     default;\n111: \n112: template \u003ctypename IRUnitT, typename... ExtraArgTs\u003e\n113: inline void\n114: AnalysisManager\u003cIRUnitT, ExtraArgTs...\u003e::clear(IRUnitT \u0026IR,\n115:                                                llvm::StringRef Name) {\n116:   if (auto *PI = getCachedResult\u003cPassInstrumentationAnalysis\u003e(IR))\n117:     PI-\u003erunAnalysesCleared(Name);\n118: \n119:   auto ResultsListI = AnalysisResultLists.find(\u0026IR);\n120:   if (ResultsListI == AnalysisResultLists.end())\n121:     return;\n122:   // Delete the map entries that point into the results list.\n123:   for (auto \u0026IDAndResult : ResultsListI-\u003esecond)\n124:     AnalysisResults.erase({IDAndResult.first, \u0026IR});\n125: \n126:   // And actually destroy and erase the results associated with this IR.\n127:   AnalysisResultLists.erase(ResultsListI);\n128: }\n129: \n130: template \u003ctypename IRUnitT, typename... ExtraArgTs\u003e\n131: inline typename AnalysisManager\u003cIRUnitT, ExtraArgTs...\u003e::ResultConceptT \u0026\n132: AnalysisManager\u003cIRUnitT, ExtraArgTs...\u003e::getResultImpl(\n133:     AnalysisKey *ID, IRUnitT \u0026IR, ExtraArgTs... ExtraArgs) {\n134:   auto [RI, Inserted] = AnalysisResults.try_emplace(std::make_pair(ID, \u0026IR));\n135: \n136:   // If we don't have a cached result for this function, look up the pass and\n137:   // run it to produce a result, which we then add to the cache.\n138:   if (Inserted) {\n139:     auto \u0026P = this-\u003elookUpPass(ID);\n140: \n141:     PassInstrumentation PI;\n142:     if (ID != PassInstrumentationAnalysis::ID()) {\n143:       PI = getResult\u003cPassInstrumentationAnalysis\u003e(IR, ExtraArgs...);\n144:       PI.runBeforeAnalysis(P, IR);\n145:     }\n146: \n147:     AnalysisResultListT \u0026ResultList = AnalysisResultLists[\u0026IR];\n148:     ResultList.emplace_back(ID, P.run(IR, *this, ExtraArgs...));\n149: \n150:     PI.runAfterAnalysis(P, IR);\n151: \n152:     // P.run may have inserted elements into AnalysisResults and invalidated\n153:     // RI.\n154:     RI = AnalysisResults.find({ID, \u0026IR});\n155:     assert(RI != AnalysisResults.end() \u0026\u0026 \"we just inserted it!\");\n156: \n157:     RI-\u003esecond = std::prev(ResultList.end());\n158:   }\n159: \n160:   return *RI-\u003esecond-\u003esecond;\n161: }\n162: \n163: template \u003ctypename IRUnitT, typename... ExtraArgTs\u003e\n164: inline void AnalysisManager\u003cIRUnitT, ExtraArgTs...\u003e::invalidate(\n165:     IRUnitT \u0026IR, const PreservedAnalyses \u0026PA) {\n166:   // We're done if all analyses on this IR unit are preserved.\n167:   if (PA.allAnalysesInSetPreserved\u003cAllAnalysesOn\u003cIRUnitT\u003e\u003e())\n168:     return;\n169: \n170:   // Track whether each analysis's result is invalidated in\n171:   // IsResultInvalidated.\n172:   SmallDenseMap\u003cAnalysisKey *, bool, 8\u003e IsResultInvalidated;\n173:   Invalidator Inv(IsResultInvalidated, AnalysisResults);\n174:   AnalysisResultListT \u0026ResultsList = AnalysisResultLists[\u0026IR];\n175:   for (auto \u0026AnalysisResultPair : ResultsList) {\n176:     // This is basically the same thing as Invalidator::invalidate, but we\n177:     // can't call it here because we're operating on the type-erased result.\n178:     // Moreover if we instead called invalidate() directly, it would do an\n179:     // unnecessary look up in ResultsList.\n180:     AnalysisKey *ID = AnalysisResultPair.first;\n181:     auto \u0026Result = *AnalysisResultPair.second;\n182: \n183:     auto IMapI = IsResultInvalidated.find(ID);\n184:     if (IMapI != IsResultInvalidated.end())\n185:       // This result was already handled via the Invalidator.\n186:       continue;\n187: \n188:     // Try to invalidate the result, giving it the Invalidator so it can\n189:     // recursively query for any dependencies it has and record the result.\n190:     // Note that we cannot reuse 'IMapI' here or pre-insert the ID, as\n191:     // Result.invalidate may insert things into the map, invalidating our\n192:     // iterator.\n193:     bool Inserted =\n194:         IsResultInvalidated.insert({ID, Result.invalidate(IR, PA, Inv)}).second;\n195:     (void)Inserted;\n196:     assert(Inserted \u0026\u0026 \"Should never have already inserted this ID, likely \"\n197:                        \"indicates a cycle!\");\n198:   }\n199: \n200:   // Now erase the results that were marked above as invalidated.\n201:   if (!IsResultInvalidated.empty()) {\n202:     for (auto I = ResultsList.begin(), E = ResultsList.end(); I != E;) {\n203:       AnalysisKey *ID = I-\u003efirst;\n204:       if (!IsResultInvalidated.lookup(ID)) {\n205:         ++I;\n206:         continue;\n207:       }\n208: \n209:       if (auto *PI = getCachedResult\u003cPassInstrumentationAnalysis\u003e(IR))\n210:         PI-\u003erunAnalysisInvalidated(this-\u003elookUpPass(ID), IR);\n211: \n212:       I = ResultsList.erase(I);\n213:       AnalysisResults.erase({ID, \u0026IR});\n214:     }\n215:   }\n216: \n217:   if (ResultsList.empty())\n218:     AnalysisResultLists.erase(\u0026IR);\n219: }\n220: } // end namespace llvm\n221: \n222: #endif // LLVM_IR_PASSMANAGERIMPL_H\n223: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/llvm-project--a8f3c97d@4152de6435984e9fc55431f4d74a7470d8ac05c0/-/blob/llvm/include/llvm/IR/PassManagerImpl.h"}", "annotations": null, "meta": null}], "structuredContent": {"content": "1: //===- PassManagerImpl.h - Pass management infrastructure -------*- C++ -*-===//
